head.script:
//==================================================================================================================
// id       : fi_301_01_02b
// 이름     : 고정자산취득(업로드)
// 경로     : 회계/재무회계/고정자산
// 작 성 자 : 오영재
// 작 업 일 : 2025-12-12
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================
/*
화면 - $Id: fi_301_01_02b.jsp
    설명 - 취득한 자산을 등록(엑셀 업로드)하는 화면
    화면규칙
        1. 증빙구분에 따라 증빙입력을 제한한다.
              입력제한 사항은 증빙구분테이블(TB_FI010)에 정의
        2. 증빙의 공급가액과 부가세액의 합은 정산금액의 합계와 같아야 한다.
        3. 증빙의 공급가액과 자산 취득금액의 합계는 같아야 한다.
        4. 증빙 관리부서를 검색하여 관련 세무서가 있으면 세무서코드를 자동입력 처리한다.
        5. 자산유형에 따라 자산종류 팝업창의 조회내역을 제한한다.
              해당 자산유형만 조회되도록 한다.
        7. 자산유형의 면적관리 여부에 따라
              면적관리정보(면적/평수/지번/지목/공시지가/공시지가 기준일) 입력을 제한한다.
              면적관리여부가 1이면 입력가능 0이면 입력불가능
        8. 해당 자산종류에 따른 상각방법을 표시한다.
        9. 임시 자산번호를 생성하여 서버에서 자산과 지번/지목을 묶어서 처리할 수 있도록 한다.
        10. 해당 자산에 대한 지번/지목이 2건이상이면 팝업창에서 입력하도록 하되
                팝업창에서 저장 시 실제 저장하지 않고 자산화면에서 전표발행 버튼을 클릭할 때 저장한다.
        11. 자회사 회계 시스템 추가 
            - 자회사 여부는 귀속부서에 종속됨.
            - 자회사인 경우는 정산방법 고정(lc_outbrAcctCd) : 미지급금   
            - 자회사인 경우는  지급수단 고정(lc_reqPayMthdCd) : (20)경비이체, (30)전자결제-현금
*/

// 전역 변수
scwin.memJson = $c.data.getMemInfo();

scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;

scwin.KOREA_WON = ACConstants.KOREA_WON;       //원화코드
scwin.ADJM_MTHDCD_PREPAY = ACConstants.ADJM_MTHDCD_PREPAY; //정산방법 - 선급금
scwin.ADJM_MTHDCD_SUSPAY = ACConstants.ADJM_MTHDCD_SUSPAY; //정산방법 - 가지급금
scwin.ADJM_MTHDCD_NOPAY = ACConstants.ADJM_MTHDCD_NOPAY;   //정산방법 - 미지금금
scwin.IsRowPosChange = false;             //면적관리 대상 자산의 지번입력을 제어하기 위한 flag
scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.rowCopyYn = 0;           // 행복사여부
scwin.checkExchRt = 0;		//환율 부분 추가
//var checkExchRt2 = 0;

scwin.checkMain = false;
scwin.uploadYn = "";  //엑셀업로드 여부

//hidden
scwin.hid_asetKndCd = "";
scwin.hid_asetKndNm = "";
scwin.hid_supplierCrn = "";
scwin.hid_cardNo = "";
scwin.hid_vatDeclarAcctDeptCd = "";
scwin.hid_adjmAcctDeptCd = "";
scwin.hid_clntNo = "";
scwin.hid_clntNo1 = "";
scwin.hid_lsClntNo = "";
scwin.hid_acqAcctDeptCd = "";
scwin.txt_clntNm1 = "";
scwin.txtCoCd;
scwin.txtCoClsCd;

scwin.onpageload = async function () {

    const codeOptions = [
        { grpCd: "FI005", compID: "lc_deductClsCd" },
        { grpCd: "FI003", compID: "lc_outbrAcctCd" },
        { grpCd: "ZZ006", compID: "lc_payCrcCd, lc_crcCd" },
        { grpCd: "FM018", compID: "lc_reqPayMthdCd" },
        { grpCd: "FI028", compID: "lc_acqCls" }
        // { grpCd: "FI111", compID: "lc_evidFileClsCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    //f_EvidHeaderCreate();               //증빙 데이터셋 생성
    //f_AsetHeaderCreate();               //자산 데이터셋 생성
    //f_LandHeaderCreate(ds_landinfo);    //지번/지목 데이터셋 생성
    //f_AdjustmentHeaderCreate();         //정산 데이터셋 생성
    //f_PrepayHeaderCreate();             //선급금 데이터셋 생성
    //f_ExchRtHeaderCreate();             //환율조회 데이터셋 생성
    //f_AdjustmentOnOff(false);         //정산입력 disable
    //f_AsetOnOff(false);                   //자산입력 disable
    //f_ExcelHeader();					//엑셀 업로드 데이터셋 생성       

    //증빙종류 조회
    //ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
    //+ "&queryId=retrieveEvidInfo&param3=PCHS";
    //ds_evidClsCd.Reset(); 
    await $c.sbm.execute(sbm_evidClsCd);

    //자산유형 조회
    await $c.sbm.execute(sbm_asetPattern);
};

scwin.ondataload = function () {

    // <%= GauceUtil.getCodeList("FM018",2,"10") %>,<%= GauceUtil.getCodeList("FM018",2,"20") %>,<%= GauceUtil.getCodeList("FM018",2,"30") %>">
    let dltStr = "dlt_commonCodeFI003"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd2 == '1'");  //$c.data.dataListFilter 함수를 이용해서 필터

    dltStr = "dlt_commonCodeFM018"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd1 == '10' || fltrCd1 == '20' || fltrCd1 == '30'");  //$c.data.dataListFilter 함수를 이용해서 필터

    //원으로 세팅
    lc_payCrcCd.setValue(scwin.KOREA_WON);

    $c.gus.cfTurnCreateFlag(false);
    lc_evidClsCd.focus();
    $c.gus.cfDisableObjects([ed_payAmtFcrc]);
    //ed_payAmtFcrc.Text = 0; 
    ed_clntNo1.hide();
    lc_acqCls.setSelectedIndex(0);
    $c.gus.cfDisableObjects([ed_acqClsStdt, ed_acqClsEnddt, ed_lsClntNo, btn_lsClnt, ed_lsTerm]);
    ed_lsClntNo.setValue("");
    ed_lsClntNm.setValue("");
    ed_acqClsStdt.setValue("");
    ed_acqClsEnddt.setValue("");
    ed_lsTerm.setValue("");
    ds_evidence.setCellData(0, "evidFileClsCd", "00");
    // default setting
    ed_vat.setValue(0); //증빙 부가세액
    ed_adjustExchRt.setValue(0); // 정산 통화코드/환율
    ed_payAmtFcrc.setValue(0);// 정산 외화
    ed_reqAmt.setValue(0);// 정산 정산금액


    //사업자번호 포맷 세팅
    ed_supplierCrn.setEditFormat('###-##||###-##-#####');
    ed_cardNo.setEditFormat('####-####||####-####-####||####-####-####-####');
    ed_zip.setEditFormat('###-###||###-##');

    //AsIs랑 화면을 맞추려는데 ref를 걸면 셀렉트 박스는 작동을 안함 (바꿔도 안바뀜)
    //ref를 풀면 index -1 을 줘야 empty 가 될텐데 change 이벤트 탐.
    // 그래서 끊고 값넣은 후 이벤트 별도 바인딩
    lc_outbrAcctCd.setSelectedIndex(-1);
    lc_outbrAcctCd.bind("onchange", scwin.lc_outbrAcctCd_onchange);
    lc_reqPayMthdCd.setSelectedIndex(-1);
}

scwin.btn_template_onclick = function (e) {
    //$c.gus.cfDownloadFile('고정자산취득템플릿.xlsx', '/ui/ac/fi/gnrlaccount/slipmgnt/fi_301_01_02b.xlsx');

    var fileName = '고정자산취득템플릿.xlsx';
    var filePath = 'ac/fi/gnrlaccount/slipmgnt/fi_301_01_02b.xlsx';
    $c.gus.cfDownloadFile(fileName, filePath);
};

scwin.udc_asetKndCd_onclickEvent = function (e) {
    scwin.f_asetKndPopUp('T');
};

//-------------------------------------------------------------------------
// 자산종류코드팝업
//-------------------------------------------------------------------------
scwin.f_asetKndPopUp = function (sIsEvent) {
    if (lc_asetPatternCd.getValue() == "") {
        $c.gus.cfAlertMsg("자산유형을 선택해 주십시요.");
        lc_asetPatternCd.focus();
        return;
    }

    if (sIsEvent == 'F') {
        ed_asetKndNm.setValue("");
        scwin.hid_asetKndNm = "";
    }/* else {
        if (f_IsPopUp(txt_asetKndNm, hid_asetKndNm, hid_asetKndCd)==false)
            return;
    } */
    /*        var rtnList = f_PopUp(hid_asetKndCd.value, txt_asetKndNm
                            , hid_asetKndNm, txt_fixedAsetNm
                            , sIsEvent, "retrieveAsetKndInfo"
                            , f_GetPatternCd(lc_asetPatternCd.Index) + ",1,1"
                            , "410"); */


    udc_asetKndCd.cfCommonPopUp(scwin.udc_asetKndCd_callbackfunc, "", ed_asetKndNm.getValue()
        , sIsEvent, null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_asetKndCd_callbackfunc = async function (rtnList) {
    console.log(rtnList)
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            ed_asetKndNm.focus();
            return;
        }
        // 이름 명 순서 다른거
        ed_asetKndNm.setValue(rtnList[1]);
        ed_asetKndNm.options.hidVal = rtnList[1];
        ed_asetKndCd.setValue(rtnList[0]);
        scwin.hid_asetKndNm = rtnList[1];

        await scwin.f_SrchAsetKnd(rtnList[0]);
    } else {
        //ds_asetKnd.ClearData();
        ds_asetKnd.removeAll();
        ed_asetKndNm.options.hidVal = "";
        ed_asetKndNm.focus();
    }
}

//-------------------------------------------------------------------------
// 자산종류 조회
//-------------------------------------------------------------------------
scwin.f_SrchAsetKnd = async function (asetKndCd) {
    var asetPatternCd = ds_excelUp.getCellData(ds_excelUp.getRowPosition(), 'asetPatternCd')
    let strAction = "/ac.fi.fixedaset.RetrieveFixedAsetKndListCMD.do?asetPatternCd=" + asetPatternCd
        + "&asetKndCd=" + asetKndCd;


    sbm_asetKnd.action = strAction;
    var res = await $c.sbm.execute(sbm_asetKnd);


    let rowCnt = ds_asetKnd.getRowCount();
    if (rowCnt == 0) {
        $c.gus.cfAlertMsg("자산종류가 존재하지 않습니다.");
        ds_asetKnd.removeAll();
    } else if (rowCnt == 1) {
        //getRowCount 는 1이라도 index는 0 부터 
        ds_asetKnd.setRowPosition(0);
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprMthdCd", ds_asetKnd.getCellData(0, "deprMthdCd"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprMthdNm", ds_asetKnd.getCellData(0, "deprMthdNm"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "svcLife", ds_asetKnd.getCellData(0, "svcLife"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "deprRt", ds_asetKnd.getCellData(0, "deprRt"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprMthdCd", ds_asetKnd.getCellData(0, "taxLawDeprMthdCd"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprMthdNm", ds_asetKnd.getCellData(0, "taxLawDeprMthdNm"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawSvcLife", ds_asetKnd.getCellData(0, "taxLawSvcLife"));
        ds_excelUp.setCellData(ds_excelUp.getRowPosition(), "taxLawDeprRt", ds_asetKnd.getCellData(0, "taxLawDeprRt"));
        //txt_fixedAsetNm.focus();
    } else {
        ds_asetKnd.removeAll();
        //if(cfCheckCreateFlag() == false) txt_asetKndNm.focus();
    }
}

//사업자번호
scwin.udc_supplierCrn_onclickEvent = function (e) {
    scwin.f_crnPopUp('F');
};

//-------------------------------------------------------------------------
// 사업자번호팝업
//-------------------------------------------------------------------------
scwin.f_crnPopUp = function (sIsEvent) {
    let selectID = 'retrieveCrnInfo';
    let param = '';

    if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {   // 자회사 회계 시스템 
        selectID = 'retrieveCrnClntInfo';
        param = "," + scwin.vCoCd;
    }
    scwin.f_PopUp('1', ed_supplierCrn, ed_supplierNm, scwin.hid_supplierCrn, null, sIsEvent, selectID, param, null);
}

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = function (flag, cdObj, nmObj, hidObj, nextObj, sIsEvent, sQueryID, sWhere, sWidth) {
    let param1, param2;

    /*
    if (cdObj.tagName == "OBJECT") {
        param1 = f_GetObjValue(cdObj);
        param2 = "";
        bReverse = false;
    } else {
        param1 = "";
        param2 = f_GetObjValue(nmObj);
        bReverse = true;
    }
    */
    if (cdObj.getValue() != "") {
        param1 = cdObj.getValue();
        param2 = "";
        //bReverse = false;
    } else {
        param1 = "";
        param2 = nmObj.getValue();
        //bReverse = true;
    }

    if (flag == "1") {  //사업자 
        udc_supplierCrn.setSelectId(sQueryID);
        udc_supplierCrn.cfCommonPopUp(scwin.udc_supplierCrn_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
    else if (flag == "2") {  //카드번호
        udc_cardNo.setSelectId(sQueryID);
        udc_cardNo.cfCommonPopUp(scwin.udc_cardNo_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
    else if (flag == "3") {  //정산귀속부서
        udc_adjmAcctDeptCd.setSelectId(sQueryID);
        udc_adjmAcctDeptCd.cfCommonPopUp(scwin.udc_adjmAcctDeptCd_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
    else if (flag == "4-1") {  //정산처
        udc_clntNo.setSelectId(sQueryID);
        udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
    else if (flag == "4-3") {  //리스/할부거래처
        udc_lsClntNo.setSelectId(sQueryID);
        udc_lsClntNo.cfCommonPopUp(scwin.udc_lsClntNo_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
    else if (flag == "5") {  //자산귀속부서
        udc_acqAcctDeptCd.setSelectId(sQueryID);
        udc_acqAcctDeptCd.cfCommonPopUp(scwin.udc_acqAcctDeptCd_callbackfunc, param1, param2, sIsEvent, null, null, null, null, sWhere, sWidth, null, null, null);
    }
}

//-------------------------------------------------
// callbackfunc list
//-------------------------------------------------
//1
scwin.udc_supplierCrn_callbackfunc = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_supplierCrn.setValue(rtnList[0]);	// 코드
        ed_supplierNm.setValue(rtnList[1]);	// 명
        ed_supplierCrn.options.hidVal = rtnList[0];  // 히든값
    } else {
        ed_supplierCrn.setValue("");
        ed_supplierNm.setValue("");
        ed_supplierCrn.options.hidVal = "";
    }
}
