scwin.f_setAdjmMethod = function () {

    if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {   // 자회사 회계 시스템 
        //lc_outbrAcctCd.CBData = "2^미지급금";   //정산방법
        lc_outbrAcctCd.removeAll();  // 콤보박스 클리어
        lc_outbrAcctCd.addItem("2", "미지급금", 0, true);

        //lc_reqPayMthdCd.CBData = "20^경비이체,30^전자결제-현금";
        lc_reqPayMthdCd.removeAll();  // 콤보박스 클리어
        lc_reqPayMthdCd.addItem("20", "경비이체", 0, true);
        lc_reqPayMthdCd.addItem("30", "전자결제-현금", 0, true);
    } else {
        //lc_outbrAcctCd.CBData ="<%= GauceUtil.getCodeList("FI003",2,"1") %>";
        //lc_reqPayMthdCd.CBData = "<%=GauceUtil.getCodeList("FM018",1, "10") %>" ;
        const codeOptions = [
            { grpCd: "FI003", compID: "lc_outbrAcctCd" },
            { grpCd: "FM018", compID: "lc_reqPayMthdCd" }
        ];
        $c.data.setCommonCode(codeOptions);
    }

    $c.gus.cfInitObjects([scwin.hid_supplierCrn, ed_supplierCrn, ed_supplierNm]); // 사업자 번호
    $c.gus.cfInitObjects([scwin.hid_cardNo, ed_cardNo, ed_cardNm]); //카드 번호 
    $c.gus.cfInitObjects([scwin.hid_vatDeclarAcctDeptCd, ed_vatDeclarAcctDeptCd, ed_vatDeclarAcctDeptNm, ed_vatSpplierCrn]); //부가세관리부서 
    $c.gus.cfInitObjects([scwin.hid_adjmAcctDeptCd, ed_adjmAcctDeptCd, ed_adjmAcctDeptNm]); //정산귀속부서
    $c.gus.cfInitObjects([scwin.hid_clntNo, ed_clntNo, ed_clntNm]); //정산처  
}

