//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_SaveProc = async function () {
    let evidFileClsCd = ds_evidence.getCellData(0, "evidFileClsCd");

    if (fileUploadGDS.getRowCount() > 0) {
        if (evidFileClsCd == "" || evidFileClsCd == "00") {
            $c.win.alert("증빙파일구분을 선택하세요");
            return;
        }
    }

    let changeExchRt;
    for (var i = 0; i < ds_adjustment.getRowCount(); i++) {
        if (lc_payCrcCd.getValue() != scwin.KOREA_WON) {
            changeExchRt = ds_adjustment.getCellData(i, "exchRt");

            dma_exchRtSearch.set("crcCd", ds_adjustment.getCellData(i, "payCrcCd"));
            dma_exchRtSearch.set("stdDt", ed_acqDt.getValue());
            //dma_exchRtSearch.UseChangeInfo = false;
            //tr_exchRt.Post();
            await $c.sbm.execute(sbm_exchRt);

            //alert( i + " => " + ds_exchRtSearch.text);
            scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt");	// 기준 환율			

            //alert(i + "번째 checkExchRt2 : " + checkExchRt);
            //alert(i + "번째 changeExchRt : " + changeExchRt);	    

            if (changeExchRt < checkExchRt * 0.9 || changeExchRt > checkExchRt * 1.1) {
                $c.win.alert('통화코드 선택시 환율 금액 : ' + scwin.checkExchRt + '원' + '\n' +
                    '환율의 90%  가 되는 금액  : ' + Math.round((scwin.checkExchRt * 0.9) * 100) / 100.00 + '원' + '\n' +
                    '환율의 110% 가 되는 금액  : ' + Math.round((scwin.checkExchRt * 1.1) * 100) / 100.00 + '원' + '\n' + '\n' +
                    i + "번째행에 입력된 환율은 기준 환율의 " + '\n' + "90% ~ 110% 사이의 값 이어야 합니다.");
                return;
            }
        }
    }

    let ret;


    if (ds_evidence.getModifiedIndex().length < 1) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, Array("자료"));
    } else {
        //입력 validation

        ret = await scwin.f_Validation();

        if (!ret) {
            return;
        }

        ret = await $c.win.confirm(MSG_CM_CRM_001);
        if (ret) {

            // 가지급금 적요,정리일자
            for (i = 0; i < ds_prov.getRowCount(); i++) {
                for (j = 0; j < ds_provHeader.getRowCount(); j++) {
                    if (ds_prov.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
                        ds_prov.setCellData(i, "summary", ds_provHeader.getCellData(j, "summary"));
                        ds_prov.setCellData(i, "setlDt", ds_provHeader.getCellData(j, "setlDt"));
                        ds_prov.setCellData(i, "bankbookNo", ds_provHeader.getCellData(j, "bankbookNo"));
                        break;
                    }
                }
            }

            //tr_master.post();
            $c.sbm.execute(sbm_master);

            ds_evidence.removeAll();            //증빙 데이터셋
            ds_aset.removeAll();                //자산 데이터셋
            ds_adjustment.removeAll();          //정산 데이터셋
            ds_landinfo.removeAll();            //지번 데이터셋
            ds_provHeader.removeAll();          //선급금 헤더 데이터셋
            ds_prov.removeAll();                //선급금 내역 데이터셋
            ds_master.removeAll();				//지번 데이터셋	                 
            ds_excelUp.removeAll();				//엑셀 업로드 데이터셋			        
            //f_OnLoad();

            strPath = "/ui/ac/fi/fixedaset/fi_301_01_02b.xml";
            menuNm = "고정자산취득(업로드)";
            menuId = "fi_301_01_02b";
            paramObj = {}
            $c.win.openMenu(menuNm, strPath, menuId, paramObj, { openAction: "exist" });
        }
    }
}

//-------------------------------------------------------------------------
// 입력 Validation
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {

    let ret;

    ret = await scwin.f_ValidateEvidence();
    if (ret == false)
        return false;

    ret = await scwin.f_ValidateAdjustment();
    if (ret == false)
        return false;

    ret = await scwin.f_ValidateAset();
    if (ret == false)
        return false;

    ret = await scwin.f_ValidateAreaMgnt();
    if (ret == false)
        return false;

    let outbrCheck = 0;
    let etcCheck = 0;
    let reqAmt = 0;

    for (i = 0; i < ds_excelUp.getRowCount(); i++) {
        if (ds_excelUp.getCellData(i, "outbrAcctCd") == "7" || ds_excelUp.getCellData(i, "outbrAcctCd") == "5") {
            outbrCheck = outbrCheck + 1;
        } else {
            reqAmt = ds_excelUp.getCellData(i, "reqAmt");
            etcCheck = etcCheck + 1;
        }
    }

    //정산금액 합계와 공급가액 비교
    let row = ds_evidence.getRowPosition();
    //        alert('ds_evidence.NameValue(row,"spplyAmt") >>> '+ds_excelUp.NameValue(row,"spplyAmt") );
    //        alert('ds_evidence.NameValue(row,"vat") >>> '+ds_excelUp.NameValue(row,"vat") );
    //        alert('ds_excelUp.NameValue(row,"reqAmt") >>> '+ ds_excelUp.NameValue(row,"reqAmt") );                
    var sum = 0;
    var compaeVal = 0;
    if (outbrCheck > 0 && etcCheck > 0) {
        sum = Number(ds_excelUp.getCellData(row, "spplyAmt")) + Number(ds_excelUp.getCellData(row, "vat"));
        compaeVal = Number(ds_excelUp.getCellData(row, "reqAmt"));
        if (sum != compaeVal) {
            $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
            //				alert('111111111');
            ed_spplyAmt.focus();
            return false;
        }
    } else {
        sum = Number(ds_excelUp.getCellData(row, "spplyAmt")) + Number(ds_excelUp.getCellData(row, "vat"));
        compaeVal = Number(ds_excelUp.getCellData(row, "reqAmt"));
        if (sum != compaeVal) {
            $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 정산금액의 합계가 틀립니다.");
            //				alert('222222222');                
            ed_spplyAmt.focus();
            return false;
        }

        //취득금액의 합계와 공급가액 비교
        if (lc_deductClsCd.getValue() == ACConstants.NO_DEDUCT_CLS_CD) {

            sum = Number(ds_excelUp.getCellData(row, "spplyAmt")) + Number(ds_excelUp.getCellData(row, "vat"));
            compaeVal = Number(ds_excelUp.getCellData(row, "acqAmt"));
            // if ((ds_excelUp.getCellData(row, "spplyAmt") + ds_excelUp.getCellData(row, "vat"))
            //  != ds_excelUp.getCellData(row, "acqAmt")) { 
            if (sum != compaeVal) {
                $c.gus.cfAlertMsg("공급가액과 부가세액의 합과 취득금액의 합계가 틀립니다.");
                //					alert('333333333333');                
                ed_spplyAmt.focus();
                return false;
            }
        } else {
            //            	alert('ed_spplyAmt.text >>>> '+ed_spplyAmt.text);
            //				alert('ds_excelUp.NameValue(row,"acqAmt") >>>' + ds_excelUp.NameValue(row,"acqAmt"));            	
            if (ed_spplyAmt.getValue() != ds_excelUp.getCellData(row, "acqAmt")) {
                $c.gus.cfAlertMsg("공급가액과 취득금액의 합계가 틀립니다.");
                ed_spplyAmt.focus();
                return false;
            }
        }
    }

    //-----------------------------------------------------------------------
    //  취득구분이 금융리스 일때 
    //	자산금액은 장기미지급금 금액과 
    //	부가세금액은 미지급금 금액과 같도록 체크 로직 
    //-----------------------------------------------------------------------

    //금융리스일때
    //alert(lc_acqCls.BindColVal);
    if (lc_acqCls.getValue() == "20") {
        //정산방법 장기미지급금-리스부채 , 미지급금
        if (lc_outbrAcctCd.getValue() != "2" && lc_outbrAcctCd.getValue() != "11") {
            //정산금액과 자산금액이 다르면 체크 
            if (ed_reqAmt.getValue() != ed_acqAmt.getValue()) {
                $c.win.alert("금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
                return false;
            }
        }

        //정산방법 미지급금
        if (lc_outbrAcctCd.getValue() == "2") {
            //부가세액과 정산금액이 다르면 체크
            if (ed_vat.getValue() != ed_reqAmt.getValue()) {
                $c.win.alert("금융리스 자산취득시 장기미지급금-리스부채는 공급가액과 일치해야 하고 미지급금은 부가세액과 일치해야 합니다.");
                return false;
            }
        }
    }

    return true;
}

