scwin.f_ValidateAset = async function () {

    let ret;

    if (ds_aset.getRowCount() < 1) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["취득자산"]);
        return false;
    }

    ret = await $c.gus.cfValidate([tbl_aset]);
    if (!ret) {
        return false;
    }

    ret = await scwin.f_ValidateAcqCls();
    if (ret == false) return false;

    return true;
}

//-------------------------------------------------------------------------
// 취득구분 Validation
// 취득구분이 금융리스(20), 할부금융(30) 일때 기간, 거래처 필수
//-------------------------------------------------------------------------
scwin.f_ValidateAcqCls = function () {

    let tempAcqCls = "";
    let cntAcctCd = 0;

    for (i = 0; i < ds_adjustment.getRowCount(); i++) {
        if (ds_adjustment.getCellData(i, "outbrAcctCd") == "11")
            cntAcctCd = cntAcctCd + 1;
    }

    if (lc_acqCls.getValue() == "20" || lc_acqCls.getValue() == "30") { 		// 금융리스(20), 할부금융(30)
        if ($c.gus.cfIsNull(ed_acqClsStdt.getValue()) || $c.gus.cfIsNull(ed_acqClsEnddt.getValue())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["리스/할부기간(이)"]);
            return false;
        }
        if ($c.gus.cfIsNull(ed_lsClntNo.getValue())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["리스/할부거래처"]);
            return false;
        }
    }

    if (lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() != "30") {
        $c.gus.cfAlertMsg("정산방법이 장기미지급금-일반인 경우 취득구분은 할부금융이여야 합니다.");
        lc_acqCls.focus();
        return false;
    } else if (lc_outbrAcctCd.getValue() != ACConstants.ADJM_MTHDCD_LONG_NOPAY && lc_acqCls.getValue() == "30") {
        $c.gus.cfAlertMsg("취득구분이 할부금융인 경우 정산방법은 장기미지급금-일반이여야 합니다.");
        lc_acqCls.focus();
        return false;
    } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() != "20") {
        $c.gus.cfAlertMsg("정산방법이 장기미지급금-리스부채인 경우 취득구분은 금융리스이여야 합니다.");
        lc_acqCls.focus();
        return false;
    } else if (cntAcctCd < 1 && lc_outbrAcctCd.getValue() != ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE && lc_acqCls.getValue() == "20") {
        $c.gus.cfAlertMsg("취득구분이 금융리스인 경우 정산방법은 장기미지급금-리스부채이여야 합니다.");
        lc_acqCls.focus();
        return false;
    } else if ((lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY_LEASE || lc_outbrAcctCd.getValue() == ACConstants.ADJM_MTHDCD_LONG_NOPAY) && lc_acqCls.getValue() == "10") {
        $c.gus.cfAlertMsg("정산방법이 장기미지급금-리스부채나 일반인 경우 취득구분은 현금을 선택 할 수 없습니다.");
        lc_acqCls.focus();
        return false;
    }

    //취득구분은 한가지로만 등록 가능 20160906 김지혜과장 요청
    for (i = 0; i < ds_aset.getRowCount(); i++) {
        if (i > 0 && (tempAcqCls != ds_aset.getCellData(i, "acqCls"))) {
            $c.gus.cfAlertMsg("취득구분은 모두 같아야합니다..");
            lc_acqCls.focus();
            return false;
        }

        tempAcqCls = ds_aset.getCellData(i, "acqCls");
    }

    return true;
}

