//-------------------------------------------------------------------------
//  가지급금,선급금 정리화면
//-------------------------------------------------------------------------
scwin.f_PrepayPopUp = async function () {

    let ret, sum;

    ret = await $c.gus.cfValidate([ed_spplyDt, ed_vatDeclarAcctDeptCd, ed_reqAmt],null,true);
    if (!ret)
        return false;

    if (lc_payCrcCd.getValue() == ACConstants.KOREA_WON)
        sum = Number(ed_reqAmt.getValue().trim());
    else
        sum = Number(ed_payAmtFcrc.getValue().trim());

    //          sum =  Number(ed_spplyAmt.text.trim())+Number(ed_vatAmt.text.trim())-Number(ed_dcAmt.text.trim());

    ds_adjustment.setCellData(ds_adjustment.getRowPosition(), "rltSeq", ds_adjustment.getRowPosition());
    //      var rltSeq = ds_adjustment.NameString(ds_adjustment.RowPosition,"rltSeq");

    var valueObject = new Object();
    valueObject.prov = ds_prov;
    valueObject.provHeader = ds_provHeader;
    valueObject.txtrltSeq = ds_adjustment.getCellData(ds_adjustment.getRowPosition(), "rltSeq");
    valueObject.adjmClsCd = lc_outbrAcctCd.getValue();          //선급금
    valueObject.compare = "2";              //팝업창의 검색방법
    valueObject.sum = sum;
    valueObject.crcCd = lc_payCrcCd.getValue();
    //valueObject.acctDeptCd = ed_vatDeclarAcctDeptCd.text.trim();
    //valueObject.acctDeptNm= txt_vatDeclarAcctDeptNm.value;

    //      var row = f_FindDataRow(ds_provHeader,"rltSeq",rltSeq);
    //valueObject.acctDeptCd = ed_adjmAcctDeptCd.Text;
    valueObject.acctDeptCd = ed_adjmAcctDeptCd.getValue();
    //valueObject.acctDeptNm = txt_adjmAcctDeptNm.value;
    valueObject.acctDeptNm = ed_adjmAcctDeptNm.getValue();

    //var style = "center:yes; dialogwidth:1000px; dialogheight:520px; scroll:no; resizable:no; status:yes;";
    //var strPath = "/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.jsp?flag=Y&slipDt=" + ed_spplyDt.text.trim();
    //var returnValue = window.showModalDialog(strPath, valueObject ,style ) ;

    let data = {
        "prov": ds_prov,
        "provHeader": ds_provHeader,
        "txtrltSeq": ds_adjustment.getCellData(ds_adjustment.getRowPosition(), "rltSeq"),
        "adjmClsCd": lc_outbrAcctCd.getValue(),
        "compare": "2",
        "sum": sum,
        "crcCd": lc_payCrcCd.getValue(),
        "acctDeptCd": ed_adjmAcctDeptCd.getValue(),
        "acctDeptNm": ed_adjmAcctDeptNm.getValue(),
        "flag" : "Y",
        "slipDt" : ed_spplyDt.getValue().trim()
    }

    let returnValue;
    const options = {
        id: "fi_201_02_02b",
        type: "browserPopup",
        modal: true,
        popupName: "가지급금입금",
        width: 1400,
        height: 760
    };
    returnValue = await $c.win.openPopup("/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml", options, data);

    if (returnValue != null) {
        ds_provHeader.ImportData(returnValue.provHeader);
        //dataSetDebug(ds_provHeader, true);
        ds_prov.ImportData(returnValue.prov);
        //dataSetDebug(ds_prov, true);
        //ds_prov.SortExpr= "+rltSeq +slipNo";
        //ds_prov.Sort();
        let sort_options = {};
        sort_options.sortIndex = "rltSeq slipNo";
        sort_options.sortOrder = "1 1";     //오른차순:"1", 내림차순"-1"
        ds_prov.multisort(sort_options);
        ds_prov.reform();

        // 중복된것 삭제
        for (i = 0; i < ds_prov.getRowCount() - 1; i++) {
            for (j = i + 1; j < ds_prov.getRowCount(); j++) {
                if (ds_prov.getCellData(i, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
                    if (ds_prov.getCellData(i, "slipNo") == ds_prov.getCellData(j, "slipNo")) {
                        //ds_prov.DeleteRow(i);
                        ds_prov.deleteRow(i);
                        break;
                    }
                }
            }
        } // for end

        //alert(ds_provHeader.NameString(1,"bankbookNm"));
        for (i = 0; i < ds_provHeader.getRowCount() - 1; i++) {
            for (j = i + 1; j <= ds_provHeader.getRowCount; j++) {
                if (ds_provHeader.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
                    ds_provHeader.deleteRow(i);
                    break;
                }
            }
        } // for end

        //debug
        //alert(ds_provHeader.text);
    }

}

//-------------------------------------------------------------------------
// 자산 취소 시 지번지목 취소 처리
//-------------------------------------------------------------------------
scwin.f_CancelLandInfo2 = function (tempAsetNo) {
    let rowCnt = 0;     //ds_landinfo 에서 tempAsetNo row count

    if (tempAsetNo == "") return;

    //row count를 구한다.
    for (var i = 0; i < ds_landinfo.getRowCount(); i++) {
        if (ds_landinfo.getCellData(i, "tempAsetNo") == tempAsetNo) {
            rowCnt++;
        }
    }

    //데이터셋의 CountRow가 변하므로 row count가 0이면 루프를 빠져나온다.
    for (var i = ds_landinfo.getRowCount(); i >= 0; i--) {
        //            if (rowCnt <= 1) {
        //                ds_landinfo.RowPosition = i;
        //                return;
        //            }
        if (ds_landinfo.getCellData(i, "tempAsetNo") == tempAsetNo) {
            ds_landinfo.deleteRow(i);
            rowCnt--;
        }
    }
}

