scwin.f_SetExchRt = async function () {
    let stdDt = ed_acqDt.getValue();
    var crcCd = lc_crcCd.getValue();

    if (crcCd == scwin.KOREA_WON) {
        ed_exchRt.setValue(0);
        ed_acqAmtFcrc.setValue(0);
        $c.gus.cfDisableObjects([ed_exchRt, ed_acqAmtFcrc]);
    } else {
        $c.gus.cfEnableObjects([ed_exchRt, ed_acqAmtFcrc]);

        if ($c.gus.cfIsNull(stdDt))
            return;

        dma_exchRtSearch.set("crcCd", crcCd);
        dma_exchRtSearch.set("stdDt", stdDt);
        //tr_exchRt.Post();
        await $c.sbm.execute(sbm_exchRt);
        //checkExchRt = ds_exchRt.NameValue(ds_exchRt.RowPosition,"stdExchRt");	// 기준 환율
        //ed_adjustExchRt.text = ds_exchRt.NameValue(1,"stdExchRt");            

    }
}

//-------------------------------------------------------------------------
// 환율 설정
//-------------------------------------------------------------------------
scwin.f_SetAdjustExchRt = async function () {
    var stdDt = scwin.g_sCurrDate;
    var crcCd = lc_payCrcCd.getValue();

    if (crcCd == scwin.KOREA_WON) {
        ed_adjustExchRt.setValue(0);
        ed_payAmtFcrc.setValue(0);
        $c.gus.cfDisableObjects([ed_adjustExchRt, ed_payAmtFcrc]);
        ed_reqAmt.setValue(0);
    } else {
        $c.gus.cfEnableObjects([ed_adjustExchRt, ed_exchRt, ed_acqAmtFcrc]);

        if ($c.gus.cfIsNull(stdDt)) return;

        dma_exchRtSearch.set("crcCd", crcCd);
        dma_exchRtSearch.set("stdDt", stdDt);
        //ds_exchRtSearch.UseChangeInfo = false;
        ed_reqAmt.setValue(0);
        ed_payAmtFcrc.setValue(0);
        //tr_exchRt.Post();
        await $c.sbm.execute(sbm_exchRt);
        scwin.checkExchRt = ds_exchRt.getCellData(ds_exchRt.getRowPosition(), "stdExchRt");	// 기준 환율
        ed_adjustExchRt.setValue(ds_exchRt.getCellData(0, "stdExchRt"));
    }
}

//-------------------------------------------------------------------------
// 취득금액 설정
//-------------------------------------------------------------------------
scwin.f_SetAcqAmt = function (crcCd) {
    if (crcCd == scwin.KOREA_WON) return;
    ed_acqAmt.setValue(Math.round(ed_exchRt.getValue() * ed_acqAmtFcrc.getValue()));
}

