scwin.f_excelUpload = async function () {
    let options = {};

    if(excelUdc.getUpExt() == "1") { // csv
        options = {
            "header": 1,
            "type": "1",
            "startRowIndex": 0,
            "footerExist": 0,
            "fileName" : "gridDataUpload.csv"
        }
    } else { // 엑셀
        options = {
            "headerExist": 1,
            "type": "1",
            "startRowIndex": 0,
            "footerExist": 0,
            "fileName" : "gridDataUpload.xlsx"
        }
    }    
    ds_excel.removeAll();
    ds_tempExcel.removeAll();
    excelUdc.uploadGridViewExcel(gr_tempExcel, options);
};

scwin.gr_excel_onfilereadend = function (value) {

    scwin.f_Upload(value);
};

//-------------------------------------------------------------------------
// 엑셀 Upload
//-------------------------------------------------------------------------
scwin.f_Upload = async function (value) {
    $c.gus.cfProgressWinOpen();

    if (ds_tempExcel.getRowCount() == 0) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    let res = await scwin.f_AddRowUploaded(value);


    if (res) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert("업로드작업이 완료되었습니다.");
    }
}


//-------------------------------------------------------------------------
// 업로드 자료 추가
//-------------------------------------------------------------------------
scwin.f_AddRowUploaded = async function () {

    // ds_temp에 ds_excel의 데이터를 받아서 수입한다. 1부터 엑셀의 총 행수까지 받아라
    // ds_temp.ImportData(ds_excel.ExportData(1,ds_excel.CountRow,true));


    // ds_excel 수입받은 총 데이터 행수가 0보다 크면
    if (gr_tempExcel.getTotalRow() > 0) {

        //toBe 바인딩 이슈로 안되는 기능이 있어 바인딩 재정의
        scwin.setBindOptions();

        ds_evidence.removeAll();            //증빙 데이터셋
        ds_aset.removeAll();                //자산 데이터셋
        ds_adjustment.removeAll();          //정산 데이터셋
        ds_landinfo.removeAll();            //지번 데이터셋
        ds_provHeader.removeAll();          //선급금 헤더 데이터셋
        ds_prov.removeAll();                //선급금 내역 데이터셋
        ds_master.removeAll();				//지번 데이터셋
        ds_tempExcel.setRowPosition(0);

        for (var i = 0; i < ds_tempExcel.getRowCount(); i++) {
            ds_evidence.insertRow();
            ds_evidence.setRowPosition(0);            //증빙 데이터셋
            ds_aset.insertRow();
            ds_aset.setRowPosition(0);                //자산 데이터셋		
            ds_adjustment.insertRow();
            ds_adjustment.setRowPosition(0);          //정산 데이터셋
            ds_landinfo.insertRow();
            ds_landinfo.setRowPosition(0);            //지번 데이터셋
            ds_provHeader.insertRow();
            ds_provHeader.setRowPosition(0);          //선급금 헤더 데이터셋
            ds_prov.insertRow();
            ds_prov.setRowPosition(0);                //선급금 내역 데이터셋
            ds_master.insertRow();
            ds_master.setRowPosition(0);				 //지번 데이터셋
            ds_excelUp.insertRow();             //업로드 내역 데이터셋		        
            var excelUpRowCnt = ds_excelUp.getRowCount();
            ds_excelUp.setRowPosition(excelUpRowCnt - 1);
            gr_excelUp.setFocusedCell(excelUpRowCnt - 1, 0, false);
            // 증빙 데이터셋	
            var vatAcctDeptCd = ds_tempExcel.getCellData(i, 'vatDeclarAcctDeptCd');
            // 부가세 관리부서 자릿수 검사	LINE 229
            var lPadVatAcctDeptCd = vatAcctDeptCd.padStart(5, "0").substring(0, 5);//00000
            ds_evidence.setCellData(i, "vatDeclarAcctDeptCd", lPadVatAcctDeptCd);
            scwin.hid_vatDeclarAcctDeptCd = lPadVatAcctDeptCd;
