                , param, null);
            break;
        case '2':	//거리처
            await scwin.f_PopUpAsync('4-2', ed_clntNo1, scwin.txt_clntNm1
                , "T", lc_outbrAcctCd
                , sIsEvent, "retrieveClntList"
                , param, null);
            break;
        case '3':	//리스거리처
            await scwin.f_PopUpAsync('4-3', ed_lsClntNo, ed_lsClntNm
                , "T", lc_outbrAcctCd
                , sIsEvent, "retrieveClntList"
                , param, null);
            break;
        default:
            await scwin.f_PopUpAsync('4-4', ed_clntNo, ed_clntNm
                , scwin.hid_clntNo, lc_outbrAcctCd
                , sIsEvent, "retrieveClntList"
                , param, null);
            break;
    }
}


