scwin.lc_evidClsCd_onviewchange = function (info) {
    let row = ds_evidClsCd.getMatchedIndex("col1", lc_evidClsCd.getValue(), true);
    //증빙 종류에 따른 입력 컨트롤 enable/disable 처리
    let clntOnOff = (ds_evidClsCd.getCellData(row, "col3") == "1") ? true : false; //거래처
    let vatOnOff = (ds_evidClsCd.getCellData(row, "col4") == "1") ? true : false;  //부가세
    let cardOnOff = (ds_evidClsCd.getCellData(row, "col5") == "1") ? true : false; //카드번호
    let duductClsOnOff = (ds_evidClsCd.getCellData(row, "col7") == "1") ? true : false;  //공제구분
    scwin.f_EvidOnOff(clntOnOff, vatOnOff, duductClsOnOff, cardOnOff);
};

/*
<!-- 증빙종류 LuxeCombo -->
*/
scwin.lc_evidClsCd_onchange = function (info) {
    lc_deductClsCd.options.emptyItem = true;
    let row = ds_evidClsCd.getMatchedIndex("col1", lc_evidClsCd.getValue(), true);
    //증빙 종류에 따른 입력 컨트롤 enable/disable 처리
    let clntOnOff = (ds_evidClsCd.getCellData(row, "col3") == "1") ? true : false; //거래처
    let vatOnOff = (ds_evidClsCd.getCellData(row, "col4") == "1") ? true : false;  //부가세
    let cardOnOff = (ds_evidClsCd.getCellData(row, "col5") == "1") ? true : false; //카드번호
    let duductClsOnOff = (ds_evidClsCd.getCellData(row, "col7") == "1") ? true : false;  //공제구분

    $c.gus.cfEnableObj(ed_supplierCrn, clntOnOff);
    $c.gus.cfEnableObj(btn_supplierCrn, clntOnOff);
    $c.gus.cfEnableObj(lc_deductClsCd, duductClsOnOff);
    $c.gus.cfEnableObj(ed_vat, vatOnOff);
    $c.gus.cfEnableObj(ed_cardNo, cardOnOff);
    $c.gus.cfEnableObj(btn_cardNo, cardOnOff);

    if (clntOnOff == true) {
        ed_supplierCrn.validExp = "사업자번호:yes:csn";
        ed_supplierCrn.options.mandatory = true;
    } else {
        ed_supplierCrn.validExp = "사업자번호:no:csn";
        ed_supplierCrn.options.mandatory = false;
    }

    lc_deductClsCd.setValue(ds_excelUp.getCellData(ds_excelUp.getRowPosition(), "deductClsCd"));

    if (vatOnOff == true) {
        ed_vat.validExp = "부가세액:yes:minNumber=1";
        ed_vat.options.mandatory = true;
        // 이거 포지션 체인지에서 타고온다. -> component는 이전값 ds는 현제값
        var supplyAmt = Number(ds_excelUp.getCellData(ds_excelUp.getRowPosition(), "spplyAmt").trim());
        //ed_vat.setValue(Math.round(ed_spplyAmt.getValue().trim() * 0.1)); //버림->반올림 수정. 2012.07.09
        ed_vat.setValue(Math.round(supplyAmt * 0.1)); //버림->반올림 수정. 2012.07.09
    } else {
        ed_vat.validExp = "부가세액:no";
        ed_vat.options.mandatory = false;
    }

    if (cardOnOff == true) {
        //ed_cardNo.validExp="카드번호:yes:length=16";
    } else {
        ed_cardNo.validExp = "카드번호:no";
        ed_cardNo.options.mandatory = false;
    }
};


